     1→#ifndef AST_NODE_H
     2→#define AST_NODE_H
     3→
     4→#include <string>
     5→#include <vector>
     6→#include <memory>
     7→#include "../codegen/Type.h"
     8→
     9→namespace zlang {
    10→
    11→// 모든 AST 노드의 기본 클래스
    12→class ASTNode {
    13→public:
    14→    enum class NodeType {
    15→        // 리터럴
    16→        IntLiteral,
    17→        FloatLiteral,
    18→        BoolLiteral,
    19→        StringLiteral,
    20→
    21→        // 식 (Expression)
    22→        BinaryOp,
    23→        UnaryOp,
    24→        Identifier,
    25→        Call,
    26→        Assignment,
    27→
    28→        // 문 (Statement)
    29→        VarDecl,
    30→        Block,
    31→        If,
    32→        While,
    33→        Return,
    34→
    35→        // 【 Step 2: Result Type 】
    36→        ResultOk,    // Result<T, E>::Ok(value)
    37→        ResultErr,   // Result<T, E>::Err(error)
    38→        Match,       // match expression (패턴 매칭)
    39→
    40→        // 【 Step 3: Exception Handling (try-catch-finally) 】
    41→        TryCatch,    // try-catch-finally 문
    42→
    43→        // 프로그램 레벨
    44→        Function,
    45→        Program
    46→    };
    47→
    48→    NodeType type;
    49→    Type inferred_type;  // 2.3 의미분석에서 채워짐
    50→
    51→    explicit ASTNode(NodeType t) : type(t) {}
    52→    virtual ~ASTNode() = default;
    53→
    54→    virtual std::string toString() const = 0;
    55→};
    56→
    57→// ============================================================================
    58→// 리터럴 노드들
    59→// ============================================================================
    60→
    61→class IntLiteralNode : public ASTNode {
    62→public:
    63→    int64_t value;
    64→
    65→    explicit IntLiteralNode(int64_t val)
    66→        : ASTNode(NodeType::IntLiteral), value(val) {}
    67→
    68→    std::string toString() const override {
    69→        return "IntLiteral(" + std::to_string(value) + ")";
    70→    }
    71→};
    72→
    73→class FloatLiteralNode : public ASTNode {
    74→public:
    75→    double value;
    76→
    77→    explicit FloatLiteralNode(double val)
    78→        : ASTNode(NodeType::FloatLiteral), value(val) {}
    79→
    80→    std::string toString() const override {
    81→        return "FloatLiteral(" + std::to_string(value) + ")";
    82→    }
    83→};
    84→
    85→class BoolLiteralNode : public ASTNode {
    86→public:
    87→    bool value;
    88→
    89→    explicit BoolLiteralNode(bool val)
    90→        : ASTNode(NodeType::BoolLiteral), value(val) {}
    91→
    92→    std::string toString() const override {
    93→        return "BoolLiteral(" + std::string(value ? "true" : "false") + ")";
    94→    }
    95→};
    96→
    97→class StringLiteralNode : public ASTNode {
    98→public:
    99→    std::string value;
   100→
   101→    explicit StringLiteralNode(const std::string& val)
   102→        : ASTNode(NodeType::StringLiteral), value(val) {}
   103→
   104→    std::string toString() const override {
   105→        return "StringLiteral(\"" + value + "\")";
   106→    }
   107→};
   108→
   109→// ============================================================================
   110→// 연산 노드들
   111→// ============================================================================
   112→
   113→enum class BinaryOp {
   114→    Add,    // +
   115→    Sub,    // -
   116→    Mul,    // *
   117→    Div,    // /
   118→    Mod,    // %
   119→    Equal,  // ==
   120→    NotEq,  // !=
   121→    Less,   // <
   122→    Greater,// >
   123→    LessEq, // <=
   124→    GreaterEq, // >=
   125→    And,    // &&
   126→    Or,     // ||
   127→    Assign  // =
   128→};
   129→
   130→class BinaryOpNode : public ASTNode {
   131→public:
   132→    BinaryOp op;
   133→    std::shared_ptr<ASTNode> left;
   134→    std::shared_ptr<ASTNode> right;
   135→
   136→    BinaryOpNode(BinaryOp o, std::shared_ptr<ASTNode> l, std::shared_ptr<ASTNode> r)
   137→        : ASTNode(NodeType::BinaryOp), op(o), left(l), right(r) {}
   138→
   139→    std::string toString() const override {
   140→        return "BinaryOp(...)";
   141→    }
   142→};
   143→
   144→enum class UnaryOp {
   145→    Neg,    // -x (Negate)
   146→    Not,    // !x
   147→    Negate, // -x (동의어)
   148→    Address // &x (주소 연산자)
   149→};
   150→
   151→class UnaryOpNode : public ASTNode {
   152→public:
   153→    UnaryOp op;
   154→    std::shared_ptr<ASTNode> operand;
   155→
   156→    UnaryOpNode(UnaryOp o, std::shared_ptr<ASTNode> opnd)
   157→        : ASTNode(NodeType::UnaryOp), op(o), operand(opnd) {}
   158→
   159→    std::string toString() const override {
   160→        return "UnaryOp(...)";
   161→    }
   162→};
   163→
   164→// ============================================================================
   165→// 변수/함수 관련 노드들
   166→// ============================================================================
   167→
   168→class IdentifierNode : public ASTNode {
   169→public:
   170→    std::string name;
   171→
   172→    explicit IdentifierNode(const std::string& n)
   173→        : ASTNode(NodeType::Identifier), name(n) {}
   174→
   175→    std::string toString() const override {
   176→        return "Identifier(" + name + ")";
   177→    }
   178→};
   179→
   180→class CallNode : public ASTNode {
   181→public:
   182→    std::string func_name;
   183→    std::vector<std::shared_ptr<ASTNode>> arguments;
   184→
   185→    CallNode(const std::string& fname, std::vector<std::shared_ptr<ASTNode>> args)
   186→        : ASTNode(NodeType::Call), func_name(fname), arguments(args) {}
   187→
   188→    std::string toString() const override {
   189→        return "Call(" + func_name + ")";
   190→    }
   191→};
   192→
   193→class AssignmentNode : public ASTNode {
   194→public:
   195→    std::string var_name;
   196→    std::shared_ptr<ASTNode> value;
   197→
   198→    AssignmentNode(const std::string& name, std::shared_ptr<ASTNode> val)
   199→        : ASTNode(NodeType::Assignment), var_name(name), value(val) {}
   200→
   201→    std::string toString() const override {
   202→        return "Assignment(" + var_name + ")";
   203→    }
   204→};
   205→
   206→// ============================================================================
   207→// 문 노드들
   208→// ============================================================================
   209→
   210→class VarDeclNode : public ASTNode {
   211→public:
   212→    std::string var_name;
   213→    Type declared_type;
   214→    std::shared_ptr<ASTNode> init_expr;  // 초기값 (optional)
   215→
   216→    VarDeclNode(const std::string& name, const Type& type, std::shared_ptr<ASTNode> init = nullptr)
   217→        : ASTNode(NodeType::VarDecl), var_name(name), declared_type(type), init_expr(init) {}
   218→
   219→    std::string toString() const override {
   220→        return "VarDecl(" + var_name + ")";
   221→    }
   222→};
   223→
   224→class BlockNode : public ASTNode {
   225→public:
   226→    std::vector<std::shared_ptr<ASTNode>> statements;
   227→
   228→    explicit BlockNode(std::vector<std::shared_ptr<ASTNode>> stmts = {})
   229→        : ASTNode(NodeType::Block), statements(stmts) {}
   230→
   231→    std::string toString() const override {
   232→        return "Block(...)";
   233→    }
   234→};
   235→
   236→class IfNode : public ASTNode {
   237→public:
   238→    std::shared_ptr<ASTNode> condition;
   239→    std::shared_ptr<BlockNode> then_block;
   240→    std::shared_ptr<BlockNode> else_block;  // optional
   241→
   242→    IfNode(std::shared_ptr<ASTNode> cond, std::shared_ptr<BlockNode> then_b,
   243→           std::shared_ptr<BlockNode> else_b = nullptr)
   244→        : ASTNode(NodeType::If), condition(cond), then_block(then_b), else_block(else_b) {}
   245→
   246→    std::string toString() const override {
   247→        return "If(...)";
   248→    }
   249→};
   250→
   251→class WhileNode : public ASTNode {
   252→public:
   253→    std::shared_ptr<ASTNode> condition;
   254→    std::shared_ptr<BlockNode> body;
   255→
   256→    WhileNode(std::shared_ptr<ASTNode> cond, std::shared_ptr<BlockNode> b)
   257→        : ASTNode(NodeType::While), condition(cond), body(b) {}
   258→
   259→    std::string toString() const override {
   260→        return "While(...)";
   261→    }
   262→};
   263→
   264→class ReturnNode : public ASTNode {
   265→public:
   266→    std::shared_ptr<ASTNode> value;  // optional
   267→
   268→    explicit ReturnNode(std::shared_ptr<ASTNode> val = nullptr)
   269→        : ASTNode(NodeType::Return), value(val) {}
   270→
   271→    std::string toString() const override {
   272→        return "Return(...)";
   273→    }
   274→};
   275→
   276→// ============================================================================
   277→// 함수 정의 노드
   278→// ============================================================================
   279→
   280→struct Parameter {
   281→    std::string name;
   282→    Type type;
   283→};
   284→
   285→class FunctionNode : public ASTNode {
   286→public:
   287→    std::string func_name;
   288→    std::vector<Parameter> parameters;
   289→    Type return_type;
   290→    std::shared_ptr<BlockNode> body;
   291→
   292→    FunctionNode(const std::string& name, std::vector<Parameter> params,
   293→                 const Type& ret_type, std::shared_ptr<BlockNode> b)
   294→        : ASTNode(NodeType::Function), func_name(name), parameters(params),
   295→          return_type(ret_type), body(b) {}
   296→
   297→    std::string toString() const override {
   298→        return "Function(" + func_name + ")";
   299→    }
   300→};
   301→
   302→// ============================================================================
   303→// 【 Step 3: try-catch-finally 노드 】
   304→// ============================================================================
   305→
   306→/**
   307→ * CatchClause: catch 블록 정의
   308→ * catch (e: ExceptionType) { ... }
   309→ */
   310→struct CatchClause {
   311→    std::string exception_var;              // 예외 변수명 (e)
   312→    std::string exception_type;             // 예외 타입 (ExceptionType)
   313→    std::shared_ptr<BlockNode> body;        // catch 블록
   314→};
   315→
   316→/**
   317→ * TryCatchNode: try-catch-finally 문
   318→ * try { ... }
   319→ * catch (e: Exception1) { ... }
   320→ * catch (e: Exception2) { ... }
   321→ * finally { ... }
   322→ */
   323→class TryCatchNode : public ASTNode {
   324→public:
   325→    std::shared_ptr<BlockNode> try_block;           // try 블록
   326→    std::vector<CatchClause> catch_clauses;         // catch 블록들
   327→    std::shared_ptr<BlockNode> finally_block;       // finally 블록 (선택사항)
   328→
   329→    TryCatchNode(std::shared_ptr<BlockNode> try_b,
   330→                 std::vector<CatchClause> catches = {},
   331→                 std::shared_ptr<BlockNode> finally_b = nullptr)
   332→        : ASTNode(NodeType::TryCatch), try_block(try_b),
   333→          catch_clauses(catches), finally_block(finally_b) {}
   334→
   335→    std::string toString() const override {
   336→        return "TryCatch(" + std::to_string(catch_clauses.size()) + " catches" +
   337→               (finally_block ? ", finally" : "") + ")";
   338→    }
   339→};
   340→
   341→// ============================================================================
   342→// 【 Step 2: Result 타입 노드들 】
   343→// ============================================================================
   344→
   345→/**
   346→ * ResultOkNode: Result<T, E>::Ok(value)
   347→ * 성공 값을 wrapping하는 노드
   348→ */
   349→class ResultOkNode : public ASTNode {
   350→public:
   351→    std::shared_ptr<ASTNode> value;
   352→
   353→    explicit ResultOkNode(std::shared_ptr<ASTNode> val)
   354→        : ASTNode(NodeType::ResultOk), value(val) {}
   355→
   356→    std::string toString() const override {
   357→        return "Ok(" + (value ? value->toString() : "?") + ")";
   358→    }
   359→};
   360→
   361→/**
   362→ * ResultErrNode: Result<T, E>::Err(error)
   363→ * 오류 값을 wrapping하는 노드
   364→ */
   365→class ResultErrNode : public ASTNode {
   366→public:
   367→    std::shared_ptr<ASTNode> error;
   368→
   369→    explicit ResultErrNode(std::shared_ptr<ASTNode> err)
   370→        : ASTNode(NodeType::ResultErr), error(err) {}
   371→
   372→    std::string toString() const override {
   373→        return "Err(" + (error ? error->toString() : "?") + ")";
   374→    }
   375→};
   376→
   377→/**
   378→ * MatchArmNode: match의 한 가지 패턴
   379→ * match x {
   380→ *     Ok(v) => { ... },
   381→ *     Err(e) => { ... },
   382→ * }
   383→ */
   384→struct MatchArm {
   385→    std::string pattern;                        // "Ok" 또는 "Err"
   386→    std::shared_ptr<ASTNode> pattern_expr;      // Ok(v) 또는 Err(e)
   387→    std::shared_ptr<BlockNode> body;            // => 다음의 블록
   388→};
   389→
   390→/**
   391→ * MatchNode: match 표현식
   392→ * Result<T, E> 타입의 값을 패턴 매칭으로 처리
   393→ */
   394→class MatchNode : public ASTNode {
   395→public:
   396→    std::shared_ptr<ASTNode> expr;              // match 대상 (보통 Result)
   397→    std::vector<MatchArm> arms;                 // match 패턴들
   398→
   399→    MatchNode(std::shared_ptr<ASTNode> e, std::vector<MatchArm> a)
   400→        : ASTNode(NodeType::Match), expr(e), arms(a) {}
   401→
   402→    std::string toString() const override {
   403→        return "Match(" + (expr ? expr->toString() : "?") + ", " +
