    22→    Bool,       // 불린
    23→    Void,       // 반환값 없음
    24→    String,     // 문자열
    25→    // 【 Step 2: Result & Option Types 】
    26→    Result,     // Result<T, E> - 성공/실패 타입
    27→    Option,     // Option<T> - 어떤 값이거나 None
    28→    Unknown     // 알 수 없는 타입
    29→};
    30→
    31→// Z-Lang 타입 정보 (포인터, 배열 등 수정자 포함)
    32→struct Type {
