    34→
    35→    // 타입 변수 (TypeVariable)
    36→    bool is_type_var = false;
    37→
    38→    // 포인터 타입: &T
    39→    bool is_pointer = false;
    40→    Type* pointee_type = nullptr;
    41→
    42→    // 배열 타입: [T; N]
    43→    bool is_array = false;
    44→    Type* element_type = nullptr;
    45→    int array_size = 0;
    46→
    47→    // 【 Step 2: Result<T, E> 타입 】
