    49→    bool is_result = false;
    50→    Type* ok_type = nullptr;      // Result의 Ok(T) 타입
    51→    Type* err_type = nullptr;     // Result의 Err(E) 타입
    52→
    53→    // 【 Step 2: Option<T> 타입 】
    54→    bool is_option = false;
    55→    Type* value_type = nullptr;   // Option의 Some(T) 타입
    56→
    57→    // 소유권 상태
    58→    enum class OwnershipState {
    59→        Available,  // 사용 가능
    60→        Moved,      // 이동됨 (더 이상 사용 불가)
    61→        Borrowed    // 대여됨 (참조만 가능)
    62→    } ownership = OwnershipState::Available;
    63→
    64→    // 편의 함수들
    65→    bool isInteger() const {
    66→        return base == BuiltinType::I32 || base == BuiltinType::I64;
