     4→
     5→namespace zlang {
     6→
     7→CodeGenerator::CodeGenerator()
     8→    : type_checker_(std::make_unique<IntegratedTypeChecker>()) {
     9→}
    10→
    11→std::string CodeGenerator::generateExprCode(
    12→    const std::string& expr,
    13→    const std::string& expr_type) {
    14→
    15→    // 리터럴 검사
    16→    if (std::isdigit(expr[0]) || (expr[0] == '-' && expr.size() > 1)) {
    17→        return generateLiteral(expr);
    18→    }
    19→
    20→    // 변수 검사
    21→    if (expr.find('+') != std::string::npos ||
    22→        expr.find('-') != std::string::npos ||
    23→        expr.find('*') != std::string::npos ||
    24→        expr.find('/') != std::string::npos) {
    25→
    26→        // 이항 연산
    27→        std::regex op_regex(R"((\w+)\s*([\+\-\*/])\s*(.+))");
    28→        std::smatch match;
    29→
    30→        if (std::regex_match(expr, match, op_regex)) {
    31→            std::string left = match[1].str();
    32→            std::string op = match[2].str();
    33→            std::string right = match[3].str();
    34→
    35→            return generateBinaryOp(left, right, op, expr_type);
    36→        }
    37→    }
    38→
    39→    // 단순 변수
    40→    return generateVariable(expr);
    41→}
    42→
    43→std::string CodeGenerator::generateBinaryOp(
    44→    const std::string& left,
    45→    const std::string& right,
    46→    const std::string& op,
    47→    const std::string& result_type) {
    48→
    49→    std::string left_val = generateExprCode(left, result_type);
    50→    std::string right_val = generateExprCode(right, result_type);
    51→
    52→    std::string result = newRegister();
    53→    std::string llvm_type = getLLVMType(result_type);
    54→
    55→    // LLVM 연산자 매핑
    56→    std::string llvm_op;
    57→    if (op == "+") llvm_op = "add";
    58→    else if (op == "-") llvm_op = "sub";
    59→    else if (op == "*") llvm_op = "mul";
    60→    else if (op == "/") llvm_op = "sdiv";  // signed division
    61→    else return "";
    62→
    63→    current_ir_ += "  " + result + " = " + llvm_op + " " + llvm_type +
    64→                   " " + left_val + ", " + right_val + "\n";
    65→
    66→    return result;
    67→}
    68→
    69→std::string CodeGenerator::generateLiteral(const std::string& literal) {
    70→    // 리터럴은 직접 반환 (새 레지스터 필요 없음)
    71→    return literal;
    72→}
    73→
    74→std::string CodeGenerator::generateVariable(const std::string& var_name) {
    75→    // 변수는 레지스터처럼 참조 (%var_name)
    76→    return "%" + var_name;
    77→}
    78→
    79→std::string CodeGenerator::generateFunctionCode(
    80→    const std::string& func_name,
    81→    const std::vector<std::string>& param_names,
    82→    const std::vector<std::string>& param_types,
    83→    const std::string& return_type,
    84→    const std::string& body) {
    85→
    86→    std::ostringstream oss;
    87→
    88→    // 함수 시그니처
    89→    oss << generateFunctionSignature(func_name, param_names, param_types, return_type);
    90→    oss << "\n";
    91→
    92→    // 매개변수를 변수 맵에 추가
    93→    for (size_t i = 0; i < param_names.size(); ++i) {
    94→        type_checker_->bindVariable(param_names[i], param_types[i]);
    95→    }
    96→
    97→    // 본문 코드 생성
    98→    std::string body_type = type_checker_->inferExprType(body);
    99→    std::string body_code = generateExprCode(body, body_type);
   100→
   101→    // 반환 명령
   102→    oss << "  ret " << getLLVMType(return_type) << " " << body_code << "\n";
   103→    oss << "}\n\n";
   104→
   105→    std::string func_def = oss.str();
   106→    functions_.push_back(func_def);
   107→
   108→    return func_def;
   109→}
   110→
   111→std::string CodeGenerator::generateFunctionSignature(
   112→    const std::string& func_name,
   113→    const std::vector<std::string>& param_names,
   114→    const std::vector<std::string>& param_types,
   115→    const std::string& return_type) {
   116→
   117→    std::ostringstream oss;
   118→    oss << "define " << getLLVMType(return_type) << " @" << func_name << "(";
   119→
   120→    for (size_t i = 0; i < param_names.size(); ++i) {
   121→        if (i > 0) oss << ", ";
   122→        oss << getLLVMType(param_types[i]) << " %" << param_names[i];
   123→    }
   124→
   125→    oss << ") {";
   126→
   127→    return oss.str();
   128→}
   129→
   130→std::string CodeGenerator::generateModule(
   131→    const std::vector<std::string>& function_defs) {
   132→
   133→    std::ostringstream oss;
   134→
   135→    // LLVM 모듈 헤더
   136→    oss << "; Generated LLVM IR\n";
   137→    oss << "target datalayout = \"e-m:e-i64:64-f80:128-n8:16:32:64-S128\"\n";
   138→    oss << "target triple = \"x86_64-unknown-linux-gnu\"\n\n";
   139→
   140→    // 함수 정의들
   141→    for (const auto& func_def : function_defs) {
   142→        oss << func_def << "\n";
   143→    }
   144→
   145→    return oss.str();
   146→}
   147→
   148→std::string CodeGenerator::newRegister() {
   149→    return "%" + std::to_string(reg_counter_++);
   150→}
   151→
   152→std::string CodeGenerator::newBlock() {
   153→    return "bb" + std::to_string(block_counter_++);
   154→}
   155→
   156→void CodeGenerator::reset() {
   157→    reg_counter_ = 0;
   158→    block_counter_ = 0;
   159→    var_reg_map_.clear();
   160→    current_ir_.clear();
   161→    functions_.clear();
   162→}
   163→
   164→std::string CodeGenerator::getLLVMType(const std::string& zlang_type) {
   165→    if (zlang_type == "i64") return "i64";
   166→    if (zlang_type == "f64") return "double";
   167→    if (zlang_type == "String") return "i8*";
   168→    if (zlang_type == "bool") return "i1";
   169→    if (zlang_type == "void") return "void";
   170→    return "i64";  // 기본값
   171→}
   172→
   173→}  // namespace zlang
