    33→class ZLangCompiler {
    34→private:
    35→    std::string source_file;
    36→    std::string output_file;
    37→    bool verbose = false;
    38→    bool emit_ir = false;
    39→    bool emit_object = false;
    40→    bool execute = false;
    41→    std::unique_ptr<CodeGenerator> codegen;  // CodeGenerator 생명주기 관리
    42→
    43→public:
    44→    ZLangCompiler() : output_file("output.ll") {}
    45→
    46→    /**
    47→     * 명령행 인자 파싱
    48→     */
    49→    bool parseArguments(int argc, char* argv[]) {
    50→        if (argc < 2) {
    51→            printUsage(argv[0]);
    52→            return false;
    53→        }
    54→
    55→        for (int i = 1; i < argc; ++i) {
    56→            std::string arg = argv[i];
    57→
    58→            if (arg == "-o" || arg == "--output") {
    59→                if (i + 1 < argc) {
    60→                    output_file = argv[++i];
    61→                }
    62→            } else if (arg == "-v" || arg == "--verbose") {
    63→                verbose = true;
    64→            } else if (arg == "--emit-ir") {
    65→                emit_ir = true;
    66→            } else if (arg == "--emit-object") {
    67→                emit_object = true;
    68→            } else if (arg == "--execute") {
    69→                execute = true;
    70→            } else if (arg == "-h" || arg == "--help") {
    71→                printUsage(argv[0]);
    72→                return false;
    73→            } else if (arg[0] != '-') {
    74→                source_file = arg;
    75→            }
    76→        }
    77→
    78→        if (source_file.empty()) {
    79→            std::cerr << "❌ 오류: 소스 파일을 지정해주세요." << std::endl;
    80→            printUsage(argv[0]);
    81→            return false;
    82→        }
    83→
    84→        return true;
    85→    }
    86→
    87→    /**
    88→     * 사용법 출력
    89→     */
    90→    void printUsage(const char* program) {
    91→        std::cout << R"(
    92→【 Z-Lang 컴파일러 】
    93→
    94→사용법: )" << program << R"( <source.z> [옵션]
    95→
    96→옵션:
    97→  -o <file>           출력 파일명 (기본값: output.ll)
    98→  -v, --verbose       상세 출력
    99→  --emit-ir           LLVM IR 파일 생성 (.ll)
   100→  --emit-object       Object 파일 생성 (.o)
   101→  --execute           컴파일 후 실행
   102→  -h, --help          도움말
   103→
   104→예제:
   105→  zlang test.z                           # test.z 컴파일 → output.ll
   106→  zlang test.z -o test.ll --verbose      # 상세 출력
   107→  zlang test.z --emit-ir --emit-object   # IR과 Object 생성
   108→)" << std::endl;
   109→    }
