   133→    /**
   134→     * 【 Stage 1: Lexing (어휘 분석) - ✅ 2.1 완성 】
   135→     *
   136→     * 소스 코드 → 토큰 스트림
   137→     */
   138→    std::vector<Token> performLexing(const std::string& source) {
   139→        if (verbose) {
   140→            std::cout << "\n【 Stage 1: Lexing (어휘 분석) - ✅ 완성 】" << std::endl;
   141→        }
   142→
   143→        Lexer lexer(source);
   144→        auto tokens = lexer.tokenize();
   145→
   146→        // 에러 확인
   147→        for (const auto& err : lexer.getErrors()) {
   148→            if (verbose) {
   149→                std::cout << "  ⚠️  " << err << std::endl;
   150→            }
   151→        }
   152→
   153→        if (verbose) {
   154→            std::cout << "  ✅ 토큰화 완료: " << tokens.size() << "개 토큰" << std::endl;
   155→        }
   156→
   157→        return tokens;
   158→    }
   159→
   160→    /**
   161→     * 【 Stage 2: Parsing (구문 분석) - ✅ 2.2 완성 】
   162→     *
   163→     * 토큰 스트림 → AST (Abstract Syntax Tree)
   164→     */
   165→    std::shared_ptr<ProgramNode> performParsing(const std::vector<Token>& tokens) {
   166→        if (verbose) {
   167→            std::cout << "\n【 Stage 2: Parsing (구문 분석) - ✅ 완성 】" << std::endl;
   168→        }
   169→
   170→        Parser parser(tokens);
   171→        auto program = parser.parse();
   172→
   173→        // 에러 확인
   174→        for (const auto& err : parser.getErrors()) {
   175→            if (verbose) {
   176→                std::cout << "  ⚠️  " << err << std::endl;
   177→            }
   178→        }
   179→
   180→        if (verbose) {
   181→            std::cout << "  ✅ 파싱 완료: " << program->functions.size() << "개 함수" << std::endl;
   182→        }
   183→
   184→        return program;
   185→    }
