   350→    /**
   351→     * 메인 컴파일 프로세스
   352→     */
   353→    int compile() {
   354→        std::cout << "\n╔════════════════════════════════════════════════════════════════╗" << std::endl;
   355→        std::cout << "║              Z-Lang 컴파일러 v0.1 (Legend Phase 2.4)          ║" << std::endl;
   356→        std::cout << "║            「기록이 증명이다」 - 전설의 컴파일러              ║" << std::endl;
   357→        std::cout << "╚════════════════════════════════════════════════════════════════╝\n" << std::endl;
   358→
   359→        if (verbose) {
   360→            std::cout << "【 빌드 정보 】" << std::endl;
   361→            std::cout << "  소스: " << source_file << std::endl;
   362→            std::cout << "  출력: " << output_file << std::endl;
   363→            std::cout << std::endl;
   364→        }
   365→
   366→        // Stage 1: Lexing
   367→        if (verbose) std::cout << "🔄 Stage 1: 어휘 분석 중..." << std::endl;
   368→        std::string source = readSourceFile();
   369→        if (source.empty()) return 1;
   370→        std::vector<Token> tokens = performLexing(source);
   371→
   372→        // Stage 2: Parsing
   373→        if (verbose) std::cout << "🔄 Stage 2: 구문 분석 중..." << std::endl;
   374→        std::shared_ptr<ProgramNode> ast = performParsing(tokens);
   375→        if (!ast || ast->functions.empty()) {
   376→            std::cerr << "❌ 구문 분석 실패 (함수가 없습니다)" << std::endl;
   377→            // 계속 진행 (빈 프로그램도 유효함)
   378→        }
   379→
   380→        // Stage 3: Semantic Analysis
   381→        if (verbose) std::cout << "🔄 Stage 3: 의미 분석 중..." << std::endl;
   382→        if (!performSemanticAnalysis(ast)) {
   383→            std::cerr << "❌ 의미 분석 실패" << std::endl;
   384→            return 1;
   385→        }
   386→
   387→        // Stage 4: Code Generation (2.4 완료)
   388→        if (verbose) std::cout << "🔄 Stage 4: 코드 생성 중..." << std::endl;
   389→        LLVMModuleRef module = performCodeGeneration(ast);
   390→        if (!module) {
   391→            std::cerr << "❌ 코드 생성 실패" << std::endl;
   392→            return 1;
   393→        }
   394→
   395→        // Stage 5: Optimization
   396→        if (verbose) std::cout << "🔄 Stage 5: 최적화 중..." << std::endl;
   397→        if (!performOptimization(module)) {
   398→            std::cerr << "❌ 최적화 실패" << std::endl;
   399→            LLVMDisposeModule(module);
   400→            return 1;
   401→        }
   402→
   403→        // 【 Stage 4.5: WCET Analysis (최악의 경우 실행 시간 분석) 】
   404→        if (verbose) std::cout << "🔄 Stage 4.5: WCET 분석 중..." << std::endl;
   405→        WCETAnalyzer wcet_analyzer;
   406→        if (!wcet_analyzer.analyze(ast)) {
   407→            if (verbose) std::cout << "⚠️  WCET 분석 완료 (정보 제공용)" << std::endl;
   408→        } else {
   409→            wcet_analyzer.printReport();
   410→        }
   411→
   412→        // Stage 6: Emit IR
   413→        if (verbose) std::cout << "🔄 Stage 6: IR 출력 중..." << std::endl;
   414→        if (!emitIRFile(module)) {
   415→            std::cerr << "❌ IR 출력 실패" << std::endl;
   416→            LLVMDisposeModule(module);
   417→            return 1;
   418→        }
   419→
   420→        // 【 Phase 2: Backend Compilation 】
   421→        // Stage 7-9: IR → Assembly → Object → Executable
   422→
   423→        if (emit_ir) {
   424→            // IR만 생성하는 경우 (기본 동작)
   425→            if (verbose) {
   426→                std::cout << "\n【 IR 생성 완료 】" << std::endl;
   427→            }
   428→        } else {
   429→            // Backend 컴파일: Assembly, Object, Executable 생성
   430→            if (verbose) std::cout << "🔄 Backend 컴파일 시작..." << std::endl;
   431→
   432→            BackendOptions backend_opts;
   433→            backend_opts.verbose = verbose;
   434→            backend_opts.optimize = true;
   435→            backend_opts.wcet_friendly = true;  // Real-Time 최적화
   436→
   437→            BackendCompiler backend;
   438→
   439→            // 출력 파일명 결정
   440→            std::string exe_file = output_file;
   441→            if (exe_file.substr(exe_file.find_last_of(".") + 1) == "ll") {
   442→                exe_file = exe_file.substr(0, exe_file.find_last_of("."));
   443→            }
   444→            if (exe_file.empty()) {
   445→                exe_file = "a.out";
   446→            }
   447→
   448→            // Backend 컴파일 수행
   449→            if (!backend.compile(output_file, exe_file, backend_opts)) {
   450→                std::cerr << "❌ Backend 컴파일 실패" << std::endl;
   451→                for (const auto& err : backend.getErrors()) {
   452→                    std::cerr << "  - " << err << std::endl;
   453→                }
   454→                LLVMDisposeModule(module);
   455→                return 1;
   456→            }
   457→
   458→            if (verbose) {
   459→                std::cout << "✅ Backend 컴파일 완료" << std::endl;
   460→            }
   461→        }
   462→
   463→        // 정리
   464→        LLVMDisposeModule(module);
   465→
   466→        std::cout << "\n✅ 컴파일 완료!" << std::endl;
   467→        std::cout << "📄 출력: " << output_file << std::endl;
   468→
   469→        if (!emit_ir) {
   470→            std::string exe_file = output_file;
   471→            if (exe_file.substr(exe_file.find_last_of(".") + 1) == "ll") {
   472→                exe_file = exe_file.substr(0, exe_file.find_last_of("."));
   473→            }
   474→            std::cout << "🔧 실행 파일: " << exe_file << std::endl;
   475→            std::cout << "\n【 다음 단계 】" << std::endl;
   476→            std::cout << "  1. 실행: ./" << exe_file << std::endl;
   477→            std::cout << "  2. IR 확인: cat " << output_file << std::endl;
   478→        } else {
   479→            std::cout << "\n【 다음 단계 】" << std::endl;
   480→            std::cout << "  1. IR 확인: cat " << output_file << std::endl;
   481→            std::cout << "  2. Assembly 생성: llc " << output_file << " -o output.s" << std::endl;
   482→            std::cout << "  3. Object 생성: as output.s -o output.o" << std::endl;
   483→            std::cout << "  4. 실행 파일: gcc output.o -o executable" << std::endl;
   484→        }
   485→
   486→        return 0;
   487→    }
   488→};
