    56→// ============================================================================
    57→// Stage 1: LLVM IR → Assembly
    58→// ============================================================================
    59→
    60→bool BackendCompiler::compileToAssembly(const std::string& ir_file,
    61→                                       const std::string& asm_file,
    62→                                       TargetArchitecture arch,
    63→                                       bool optimize,
    64→                                       bool wcet_friendly) {
    65→    // llc (LLVM Compiler) 명령어 구성
    66→    std::string cmd = "llc";
    67→
    68→    // 1. 아키텍처 지정
    69→    cmd += " -march=" + getMarch(arch);
    70→
    71→    // 2. 최적화 레벨
    72→    // Note: LLVM 21+ doesn't support -disable-* flags, use -O level instead
    73→    if (wcet_friendly) {
    74→        // WCET-friendly 컴파일: 보수적 최적화
    75→        cmd += " -O1";
    76→    } else if (optimize) {
    77→        cmd += " -O2";  // 표준 최적화
    78→    } else {
    79→        cmd += " -O0";  // 디버그 빌드
    80→    }
    81→
    82→    // 3. 입출력 파일
    83→    cmd += " " + ir_file;
    84→    cmd += " -o " + asm_file;
    85→
    86→    return runCommand(cmd, "Assembly 생성");
    87→}
