    92→
    93→bool BackendCompiler::compileToObject(const std::string& ir_file,
    94→                                      const std::string& obj_file,
    95→                                      TargetArchitecture arch,
    96→                                      bool optimize,
    97→                                      bool wcet_friendly) {
    98→    // llc (LLVM Compiler) 명령어 구성, Object 파일 직접 생성
    99→    std::string cmd = "llc";
   100→
   101→    // 1. 아키텍처 지정
   102→    cmd += " -march=" + getMarch(arch);
   103→
   104→    // 2. Object 파일 형식 직접 생성
   105→    cmd += " -filetype=obj";
   106→
   107→    // 3. 최적화 레벨 (Stage 7-8과 동일)
   108→    if (wcet_friendly) {
   109→        cmd += " -O1";
   110→    } else if (optimize) {
   111→        cmd += " -O2";
   112→    } else {
   113→        cmd += " -O0";
   114→    }
   115→
   116→    // 4. 입출력 파일
   117→    cmd += " " + ir_file;
   118→    cmd += " -o " + obj_file;
   119→
   120→    return runCommand(cmd, "Object 파일 생성");
   121→}
