   140→bool BackendCompiler::linkToExecutable(const std::vector<std::string>& obj_files,
   141→                                      const std::string& exe_file,
   142→                                      bool static_link) {
   143→    // Clang을 링커로 사용 (GCC 호환)
   144→    std::string cmd = "clang";
   145→
   146→    // Object 파일 추가
   147→    for (const auto& obj : obj_files) {
   148→        cmd += " " + obj;
