   150→
   151→    // 정적/동적 링킹 옵션 (Termux 호환)
   152→    // -static은 대부분의 Android 시스템에서 지원되지 않으므로 생략
   153→    if (static_link) {
   154→        // cmd += " -static";  // Termux에서 지원 안 함
   155→    }
   156→
   157→    // C 표준 라이브러리
   158→    cmd += " -lc -lm";
   159→
   160→    // 출력 파일
   161→    cmd += " -o " + exe_file;
