   197→
   198→std::string BackendCompiler::getMarch(TargetArchitecture arch) const {
   199→    switch (arch) {
   200→        case TargetArchitecture::X86_64:   return "x86-64";
   201→        case TargetArchitecture::ARM64:    return "aarch64";
   202→        case TargetArchitecture::RISC_V:   return "riscv64";
   203→        case TargetArchitecture::AUTO:     {
   204→            // 자동 감지: 현재 시스템 아키텍처 감지
   205→            // llvm-config를 사용하여 현재 타겟 아키텍처 확인
   206→            FILE* pipe = popen("llvm-config --host-target", "r");
   207→            if (pipe) {
   208→                char buffer[128];
   209→                if (fgets(buffer, sizeof(buffer), pipe) != nullptr) {
   210→                    std::string target(buffer);
   211→                    // 개행 문자 제거
   212→                    if (target.back() == '\n') target.pop_back();
   213→                    pclose(pipe);
   214→
   215→                    // 아키텍처 감지
   216→                    if (target.find("aarch64") != std::string::npos) {
   217→                        return "aarch64";
   218→                    } else if (target.find("x86_64") != std::string::npos) {
   219→                        return "x86-64";
   220→                    } else if (target.find("riscv64") != std::string::npos) {
   221→                        return "riscv64";
   222→                    }
   223→                }
   224→                pclose(pipe);
   225→            }
   226→            // 기본값: aarch64 (현재 사용 환경)
   227→            return "aarch64";
   228→        }
   229→        default:                           return "aarch64";  // 기본값 변경
   230→    }
   231→}
