   238→bool BackendCompiler::runCommand(const std::string& cmd,
   239→                                const std::string& description) {
   240→    std::cout << "  🔧 " << description << "..." << std::endl;
   241→
   242→    int ret = system(cmd.c_str());
   243→
   244→    if (ret != 0) {
   245→        std::string error = description + " 실패 (Return code: " +
   246→                           std::to_string(ret) + ")";
   247→        errors.push_back(error);
   248→        std::cerr << "  ❌ " << error << std::endl;
   249→        return false;
   250→    }
   251→
   252→    return true;
   253→}
