    14→// 심볼 정보 (2.3 의미분석에서 수집됨)
    15→struct SymbolInfo {
    16→    std::string name;
    17→    Type type;
    18→    Type::OwnershipState ownership;
    19→
    20→    // 2.4 코드생성에서 사용:
    21→    // LLVM의 alloca 결과 (메모리 주소)
