    24→
    25→// 심볼 테이블: 스코프 스택으로 관리
    26→class SymbolTable {
    27→private:
    28→    // 각 스코프는 변수명 → SymbolInfo 매핑
    29→    std::vector<std::unordered_map<std::string, SymbolInfo>> scope_stack;
    30→
    31→public:
    32→    SymbolTable() {
    33→        // 전역 스코프로 시작
    34→        pushScope();
    35→    }
    36→
    37→    // 새로운 스코프 진입 (함수, 블록 등)
    38→    void pushScope() {
    39→        scope_stack.push_back({});
    40→    }
    41→
    42→    // 스코프 종료
    43→    void popScope() {
    44→        if (scope_stack.size() > 1) {
    45→            scope_stack.pop_back();
    46→        }
    47→    }
    48→
    49→    // 현재 스코프에 심볼 정의
    50→    void define(const std::string& name, const SymbolInfo& info) {
    51→        if (!scope_stack.empty()) {
    52→            scope_stack.back()[name] = info;
    53→        }
    54→    }
    55→
    56→    // 현재 스코프에서만 찾기
    57→    std::optional<SymbolInfo> lookupLocal(const std::string& name) const {
    58→        if (scope_stack.empty()) return std::nullopt;
    59→
    60→        auto& current_scope = scope_stack.back();
    61→        auto it = current_scope.find(name);
    62→        if (it != current_scope.end()) {
    63→            return it->second;
    64→        }
    65→        return std::nullopt;
    66→    }
    67→
    68→    // 모든 스코프에서 찾기 (가장 가까운 스코프부터)
    69→    std::optional<SymbolInfo> resolve(const std::string& name) const {
    70→        // 가장 최신 스코프부터 역순으로 탐색
    71→        for (auto it = scope_stack.rbegin(); it != scope_stack.rend(); ++it) {
    72→            auto sym_it = it->find(name);
    73→            if (sym_it != it->end()) {
    74→                return sym_it->second;
    75→            }
    76→        }
    77→        return std::nullopt;
    78→    }
    79→
    80→    // 심볼 업데이트 (소유권 상태 변경 등)
    81→    void update(const std::string& name, const SymbolInfo& info) {
    82→        // 가장 가까운 스코프에서 찾아서 업데이트
    83→        for (auto it = scope_stack.rbegin(); it != scope_stack.rend(); ++it) {
    84→            auto sym_it = it->find(name);
    85→            if (sym_it != it->end()) {
    86→                sym_it->second = info;
    87→                return;
    88→            }
    89→        }
    90→    }
    91→
    92→    // 현재 스코프 깊이
    93→    size_t depth() const {
    94→        return scope_stack.size();
    95→    }
    96→
    97→    // 디버깅용: 현재 스코프의 모든 심볼 출력
    98→    void dump() const {
    99→        std::cout << "=== SymbolTable (depth=" << scope_stack.size() << ") ===" << std::endl;
   100→        for (size_t i = 0; i < scope_stack.size(); ++i) {
   101→            std::cout << "Scope " << i << ":" << std::endl;
   102→            for (const auto& [name, info] : scope_stack[i]) {
   103→                std::cout << "  " << name << ": " << info.type.toString() << std::endl;
   104→            }
   105→        }
   106→    }
   107→};
   108→
   109→} // namespace zlang
   110→
   111→#endif // SYMBOL_TABLE_H
