fn fibonacci(n: i64) -> i64 {
    if n <= 1 {
        return n;
    }
    let a: i64 = 0;
    let b: i64 = 1;
    let i: i64 = 2;
    while i <= n {
        let temp: i64 = a + b;
        a = b;
        b = temp;
        i = i + 1;
    }
    return b;
}

